css:
.textcenter{
    text-align:center;
}

.borderclass{
    border-bottom: 1px solid #000; /* changed to black */
}

table {
    width:100%;
    text-align:left;
    border-collapse: collapse;
    border: 1px solid #000; /* ensure table border is black */
    font-size:10px;
}

table td {
    font-size: 12px; /* reduced slightly for consistency */
}

.col-sm-5{
    align-content: center;
    margin-left:40px;
}

p{
    font-size: 14px; /* reduced slightly for consistency */
}

.print-format{
    padding: 15px !important;
    margin: 20px !important;
    border: 2px solid #000; /* full page border */
    min-height: 95vh; /* ensures border covers full page height */
    box-sizing: border-box;
}

/* Optional: remove unwanted gaps */
.print-format > div {
    margin-top: 0 !important;
    margin-bottom: 0 !important;
}

footer{
  clear: both;
  position: relative;
  bottom:0;
  width:100%;
  text-align:center;
}

